changeSet.sql:
ALTER TABLE clinlims.notebook_page DROP CONSTRAINT IF EXISTS chk_page_type;
ALTER TABLE clinlims.notebook_page
ADD CONSTRAINT chk_page_type
CHECK (page_type IS NULL OR page_type IN ('BATCH_VERIFICATION', 'BULK_DATA_ENTRY', 'BRANCHING', 'INDIVIDUAL_PROCESSING', 'AGGREGATION', 'STORAGE_ASSIGNMENT', 'CHILD_SAMPLE_CREATION'));

rollback.sql:
ALTER TABLE clinlims.notebook_page DROP CONSTRAINT IF EXISTS chk_page_type;
ALTER TABLE clinlims.notebook_page
ADD CONSTRAINT chk_page_type
CHECK (page_type IS NULL OR page_type IN ('BATCH_VERIFICATION', 'BULK_DATA_ENTRY', 'BRANCHING', 'INDIVIDUAL_PROCESSING', 'AGGREGATION', 'STORAGE_ASSIGNMENT'));

column.value:
{
  "pageDescription": "Aliquoting / Bulk Sample Import",
  "dataPoints": {
    "aliquotDetails": {
      "aliquotType": {"type": "choice", "label": "Aliquot Type", "options": ["Tube", "Plate (96-well)", "Cryobox (9×9)", "Cryobox (10×10)"], "required": true},
      "aliquotIdPrefix": {"type": "text", "label": "Aliquot ID Prefix", "example": "MNTD-ALQ", "required": true},
      "aliquotsPerParent": {"type": "integer", "label": "Aliquots per Parent", "min": 1, "max": 20, "default": 1, "required": true}
    },
    "bulkImport": {
      "plateMapUpload": {"type": "file", "label": "Upload Plate Map", "accept": ".csv", "required": false},
      "boxLayoutUpload": {"type": "file", "label": "Upload Box Layout", "accept": ".csv", "required": false},
      "wellPositions": {"type": "wellGrid", "label": "Well Positions", "rows": 8, "columns": 12, "required": false},
      "controlSamples": {"type": "multiSelect", "label": "Control Samples", "source": "control_samples", "required": false},
      "projectAssociation": {"type": "text", "label": "Project Association", "description": "Can be mixed projects", "required": false}
    },
    "volumeQuantityTracking": {
      "initialVolume": {"type": "number", "label": "Initial Volume per Aliquot", "unit": "mL", "required": false},
      "dbsSpots": {"type": "integer", "label": "DBS Spots", "required": false},
      "remainingVolume": {"type": "number", "label": "Remaining Volume", "unit": "mL", "computed": true, "required": false},
      "remainingSpots": {"type": "integer", "label": "Remaining DBS Spots", "computed": true, "required": false}
    },
    "routeToAnalyzer": {
      "analyzerPlate": {"type": "assayPlate", "label": "Analyzer Plate", "plateTypes": ["96-well", "48-well", "24-well", "custom"], "required": false},
      "wellAssignment": {"type": "autoAssign", "label": "Well Assignment", "order": "row-major", "example": "A1, A2, ..., B1, B2, ..."}
    }
  },
  "systemActions": ["Create child sample records", "Preserve lineage: Parent → Aliquot", "Update remaining volume on parent", "Auto-generate Aliquot ID", "Route to Internal Analysis with plate assignment"],
  "bulkOperations": {
    "enabled": true,
    "applyToSelected": ["aliquotType", "aliquotsPerParent", "initialVolume"]
  },
  "nextPage": "Processing & QC"
}
